import{_ as a,o as s,c as t,ai as i}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Gateway Lifecycle","description":"","frontmatter":{"summary":"Gateway lifecycle on macOS (launchd)","read_when":["Integrating the mac app with the gateway lifecycle"],"title":"Gateway Lifecycle"},"headers":[],"relativePath":"platforms/mac/child-process.md","filePath":"platforms/mac/child-process.md","lastUpdated":1771906665000}'),n={name:"platforms/mac/child-process.md"};function l(o,e,d,r,h,c){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="gateway-lifecycle-on-macos" tabindex="-1"><a class="header-anchor" href="#gateway-lifecycle-on-macos">#</a> Gateway lifecycle on macOS</h1><p>The macOS app <strong>manages the Gateway via launchd</strong> by default and does not spawn the Gateway as a child process. It first tries to attach to an already‑running Gateway on the configured port; if none is reachable, it enables the launchd service via the external <code>opensoul</code> CLI (no embedded runtime). This gives you reliable auto‑start at login and restart on crashes.</p><p>Child‑process mode (Gateway spawned directly by the app) is <strong>not in use</strong> today. If you need tighter coupling to the UI, run the Gateway manually in a terminal.</p><h2 id="default-behavior-launchd" tabindex="-1"><a class="header-anchor" href="#default-behavior-launchd">#</a> Default behavior (launchd)</h2><ul><li>The app installs a per‑user LaunchAgent labeled <code>ai.opensoul.gateway</code> (or <code>ai.opensoul.&lt;profile&gt;</code> when using <code>--profile</code>/<code>OPENSOUL_PROFILE</code>; legacy <code>com.opensoul.*</code> is supported).</li><li>When Local mode is enabled, the app ensures the LaunchAgent is loaded and starts the Gateway if needed.</li><li>Logs are written to the launchd gateway log path (visible in Debug Settings).</li></ul><p>Common commands:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">launchctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kickstart</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -k</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gui/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$UID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/ai.opensoul.gateway</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">launchctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bootout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gui/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$UID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/ai.opensoul.gateway</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Replace the label with <code>ai.opensoul.&lt;profile&gt;</code> when running a named profile.</p><h2 id="unsigned-dev-builds" tabindex="-1"><a class="header-anchor" href="#unsigned-dev-builds">#</a> Unsigned dev builds</h2><p><code>scripts/restart-mac.sh --no-sign</code> is for fast local builds when you don’t have signing keys. To prevent launchd from pointing at an unsigned relay binary, it:</p><ul><li>Writes <code>~/.opensoul/disable-launchagent</code>.</li></ul><p>Signed runs of <code>scripts/restart-mac.sh</code> clear this override if the marker is present. To reset manually:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.opensoul/disable-launchagent</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="attach-only-mode" tabindex="-1"><a class="header-anchor" href="#attach-only-mode">#</a> Attach-only mode</h2><p>To force the macOS app to <strong>never install or manage launchd</strong>, launch it with <code>--attach-only</code> (or <code>--no-launchd</code>). This sets <code>~/.opensoul/disable-launchagent</code>, so the app only attaches to an already running Gateway. You can toggle the same behavior in Debug Settings.</p><h2 id="remote-mode" tabindex="-1"><a class="header-anchor" href="#remote-mode">#</a> Remote mode</h2><p>Remote mode never starts a local Gateway. The app uses an SSH tunnel to the remote host and connects over that tunnel.</p><h2 id="why-we-prefer-launchd" tabindex="-1"><a class="header-anchor" href="#why-we-prefer-launchd">#</a> Why we prefer launchd</h2><ul><li>Auto‑start at login.</li><li>Built‑in restart/KeepAlive semantics.</li><li>Predictable logs and supervision.</li></ul><p>If a true child‑process mode is ever needed again, it should be documented as a separate, explicit dev‑only mode.</p>`,20)])])}const g=a(n,[["render",l]]);export{u as __pageData,g as default};
